import { useState, useRef, useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Layout from "@/components/Layout";
import NavigationBar from "@/components/NavigationBar";
import Button from "@/components/Button";
import FormErrorMessage from "@/components/FormErrorMessage";
import { useUser } from "@/hooks/useUser";
import { useLoading } from "@/hooks/useLoading";
import { useLockFn } from "@/hooks/useLockFn";
import { toast } from "@/utils/toast";
import { goBack } from "@/utils/navigation";
import { useAutoFocus } from "@/hooks/useAutoFocus";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";
import SkipTaskButton from "@/pages/ProfileTask/SkipTaskButton";
import { PERCENT_BY_STEP, getTaskNextPath, getTaskPrevPath, getTaskStep } from "@/pages/ProfileTask/taskMode";

const MAX_LENGTH = 150;

export default function Bio() {
  const navigate = useNavigate();
  const location = useLocation();
  const taskMode = (location.state as { taskMode?: boolean } | null)?.taskMode === true;
  const step = getTaskStep(location.pathname);
  const nextPath = getTaskNextPath(location.pathname);
  const prevPath = getTaskPrevPath(location.pathname);
  const { userInfo, updateProfile } = useUser();
  const { showLoading, hideLoading } = useLoading();

  const [value, setValue] = useState(userInfo?.bio || "");
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useAutoFocus(textareaRef);

  // 埋点：Bio 页面展示
  useEffect(() => {
    if (taskMode) {
      bpTrack(EventName.pwa_profile_task_bio_show);
    }
  }, [taskMode]);

  const isValid = value.trim().length > 0 && value.length <= MAX_LENGTH;

  const handleChange = (text: string) => {
    setValue(text);
    setErrorMessage(text.length > MAX_LENGTH ? `Please keep it within ${MAX_LENGTH} characters` : null);
  };

  const handleSave = useLockFn(async () => {
    if (!isValid) return;
    showLoading();
    try {
      await updateProfile({ bio: value.trim() });
      if (taskMode) {
        bpTrack(EventName.pwa_profile_task_bio_continue, { bio: value.trim() });
      }
      bpTrack(EventName.pwa_profile_update_success, { field: "bio" });
      if (taskMode) {
        navigate(nextPath, { state: { taskMode: true } });
      } else {
        goBack(navigate);
      }
    } catch {
      toast.error("Save failed");
    } finally {
      hideLoading();
    }
  });

  return (
    <Layout showTabBar={false}>
      <div className="flex flex-col h-full bg-surface">
        <NavigationBar
          onBack={() =>
            taskMode
              ? navigate(prevPath, prevPath === "/" ? { replace: true } : { state: { taskMode: true } })
              : goBack(navigate)
          }
          rightSlot={taskMode ? <SkipTaskButton to={nextPath} /> : null}
        />
        {taskMode ? (
          <div className="h-1 w-full bg-white">
            <div
              className="h-full bg-[#6bc4ff] transition-all duration-300"
              style={{ width: `${PERCENT_BY_STEP[step as 0 | 1 | 2] ?? PERCENT_BY_STEP[1]}%` }}
            />
          </div>
        ) : null}

        <div className="flex-1 flex flex-col p-6">
          <div className="flex-1 flex flex-col items-center">
            <h1 className="mt-3 text-brand-dark text-xl font-bold text-center capitalize">Your bio</h1>

            <textarea
              ref={textareaRef}
              autoComplete="off"
              value={value}
              onChange={(e) => handleChange(e.target.value)}
              className="w-full h-[105px] mt-10 p-5 rounded-[14px] bg-[rgba(107,196,255,0.2)] text-brand-dark text-[15px] resize-none outline-none border border-[0.5px] border-[rgba(35,61,127,0.1)]"
            />

            {errorMessage && <FormErrorMessage message={errorMessage} className="mt-[14px]" />}
          </div>

          <Button onClick={handleSave} disabled={!isValid} variant="primary" className="shrink-0">
            {taskMode ? "Next" : "Save"}
          </Button>
        </div>
      </div>
    </Layout>
  );
}
